import{_ as a,o,c as r,ae as t}from"./chunks/framework.DeBUZsJm.js";const u=JSON.parse('{"title":"Safe Mode & Recovery","description":"","frontmatter":{},"headers":[],"relativePath":"safe-mode.md","filePath":"safe-mode.md","lastUpdated":1775513914000}'),i={name:"safe-mode.md"};function l(s,e,n,d,c,p){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="safe-mode-recovery" tabindex="-1">Safe Mode &amp; Recovery <a class="header-anchor" href="#safe-mode-recovery" aria-label="Permalink to &quot;Safe Mode &amp; Recovery&quot;">​</a></h1><p>Astrogram can switch into safe mode when a plugin crashes during a tracked operation such as install, update, load or settings entry.</p><h2 id="main-recovery-files" tabindex="-1">Main recovery files <a class="header-anchor" href="#main-recovery-files" aria-label="Permalink to &quot;Main recovery files&quot;">​</a></h2><ul><li><code>tdata/plugins.log</code></li><li><code>tdata/plugins.trace.jsonl</code></li><li><code>tdata/plugins.json</code></li><li><code>tdata/plugins.recovery.json</code></li><li><code>tdata/plugins.safe-mode</code></li></ul><h2 id="recovery-model" tabindex="-1">Recovery model <a class="header-anchor" href="#recovery-model" aria-label="Permalink to &quot;Recovery model&quot;">​</a></h2><ol><li>The plugin manager records the operation that is about to enter risky code.</li><li>If the process crashes before the operation is cleared, recovery state remains on disk.</li><li>On the next launch Astrogram can disable the implicated plugin set and enter safe mode.</li><li>The plugin remains visible in the manager so the user can inspect and remove it.</li></ol><h2 id="best-practices-for-plugin-authors" tabindex="-1">Best practices for plugin authors <a class="header-anchor" href="#best-practices-for-plugin-authors" aria-label="Permalink to &quot;Best practices for plugin authors&quot;">​</a></h2><ul><li>keep <code>onLoad()</code> small and deterministic</li><li>avoid long blocking work on the UI thread</li><li>prefer host-rendered settings pages over ad-hoc raw dialogs</li><li>log important transitions into <code>plugins.log</code></li><li>unregister handlers, timers and observers on unload</li></ul><h2 id="best-practices-for-bug-reports" tabindex="-1">Best practices for bug reports <a class="header-anchor" href="#best-practices-for-bug-reports" aria-label="Permalink to &quot;Best practices for bug reports&quot;">​</a></h2><p>Collect:</p><ul><li>client build / commit</li><li>plugin name and version</li><li><code>log.txt</code></li><li><code>tdata/plugins.log</code></li><li><code>tdata/plugins.trace.jsonl</code></li><li>whether the crash happened during install, restart or settings open</li></ul>',11)])])}const m=a(i,[["render",l]]);export{u as __pageData,m as default};
